sql:
SELECT AVG(age) AS average_age
FROM household_members
WHERE occupation = 'Business';

SELECT *
FROM household_members
WHERE household_id = 'Desired Household ID';

SELECT 
    (SELECT COUNT(*) FROM households) AS total_castles,
    (SELECT COUNT(*) FROM household_members) AS total_knights;

SELECT COUNT(DISTINCT household_id)
FROM households
WHERE depressed = 1;

SELECT COUNT(*)
FROM households
WHERE total_members > 1 AND depressed = 1;

SELECT ville_name, population
FROM villages
WHERE ville_name LIKE '%City%';

external_knowledge:
- "thriving families" refers to households where the head is unmarried and not experiencing depression;
- "blossoms of independence and vitality" metaphorically refers to the households where the head is single and the household is not depressed;
- "rich soil in terms of income and assets" signifies the total income and assets within each region;
- "fertile is their harvest when comparing income to assets" metaphorically represents the income-to-assets ratio.
